 // ─── Particle system ───────────────────────────────────────────────

 interface Particle { x: number; y: number; vx: number; vy: number; life: number; maxLife: number; color: string; size: number }
 const particlePool = new Map<string, Particle[]>();
 function getParticles(id: string) { if (!particlePool.has(id)) particlePool.set(id, []); return particlePool.get(id)!; }
 function spawnParticle(id: string, x: number, y: number, color: string, vx = 0, vy = -0.5, size = 2, life = 60) {
   const p = getParticles(id);
   if (p.length > 30) return;
   p.push({ x, y, vx: vx + (Math.random() - 0.5) * 0.3, vy, life, maxLife: life, color, size });
 }
 function updateAndDrawParticles(ctx: CanvasRenderingContext2D, id: string) {
   const arr = getParticles(id);
   for (let i = arr.length - 1; i >= 0; i--) {
     const p = arr[i];
     p.x += p.vx; p.y += p.vy; p.life--;
     if (p.life <= 0) { arr.splice(i, 1); continue; }
     ctx.globalAlpha = p.life / p.maxLife;
     ctx.fillStyle = p.color;
     ctx.fillRect(Math.round(p.x), Math.round(p.y), p.size, p.size);
   }
   ctx.globalAlpha = 1;
 }

 // ─── Character movement ────────────────────────────────────────────

 interface CharState { x: number; y: number; tx: number; ty: number; dir: string; wf: number; moving: boolean; idle: number }
 const charStates = new Map<string, CharState>();

 function getCS(id: string, sx: number, sy: number): CharState {
   if (!charStates.has(id)) charStates.set(id, { x: sx, y: sy, tx: sx, ty: sy, dir: 'down', wf: 0, moving: false, idle: Math.random() * 200 });
   return charStates.get(id)!;
 }

 function updateMovement(cs: CharState, bounds: { x: number; y: number; w: number; h: number }) {
   const dx = cs.tx - cs.x, dy = cs.ty - cs.y;
   const dist = Math.sqrt(dx * dx + dy * dy);
   if (dist > 2) {
     cs.moving = true;
     cs.x += (dx / dist) * 0.4;
     cs.y += (dy / dist) * 0.4;
     cs.wf++;
     cs.dir = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'right' : 'left') : (dy > 0 ? 'down' : 'up');
   } else {
     cs.moving = false; cs.wf = 0; cs.idle--;
     if (cs.idle <= 0) {
       const mx = bounds.w * 0.15, my = bounds.h * 0.2;
       cs.tx = bounds.x + mx + Math.random() * (bounds.w - mx * 2);
       cs.ty = bounds.y + my + Math.random() * (bounds.h - my * 2);
       cs.idle = 150 + Math.random() * 300;
     }
   }
 }

 // ─── Speech bubbles ────────────────────────────────────────────────

 const QUIPS = ['For the realm!', 'By decree...', 'Hmm...', 'The scrolls speak.', 'Guards!', 'Fascinating.', 'Another day...', 'The kingdom grows.', 'To battle!', 'Justice prevails.', 'The forge calls.', 'Heal thyself.'];
 interface Bubble { text: string; timer: number; kind: 'speech' | 'thought' }
 const bubbles = new Map<string, Bubble>();

 function updateBubble(id: string, state: AnimState, job: string | null, frame: number) {
   const b = bubbles.get(id);
   if (b) { b.timer--; if (b.timer <= 0) bubbles.delete(id); return; }
   if (state === 'working' && job && frame % 300 < 2) {
     bubbles.set(id, { text: job.length > 28 ? job.substring(0, 26) + '..' : job, timer: 180, kind: 'speech' });
   } else if (state === 'idle' && frame % 500 < 2) {
     bubbles.set(id, { text: QUIPS[Math.floor(Math.random() * QUIPS.length)], timer: 120, kind: 'thought' });
   }
 }

 function drawBubble(ctx: CanvasRenderingContext2D, id: string, x: number, y: number) {
   const b = bubbles.get(id);
   if (!b) return;
   ctx.globalAlpha = b.timer < 30 ? b.timer / 30 : 1;
   ctx.font = '9px monospace';
   const tw = ctx.measureText(b.text).width;
   const bw = tw + 12, bh = 18, bx = x - bw / 2, by = y - bh - 8;
   // Background
   ctx.fillStyle = b.kind === 'speech' ? '#f0ead6' : '#d8e8f8';
   ctx.strokeStyle = '#2a2020'; ctx.lineWidth = 1.5;
   roundRect(ctx, bx, by, bw, bh, 4); ctx.fill(); ctx.stroke();
   // Tail
   ctx.beginPath();
   ctx.moveTo(x - 4, by + bh); ctx.lineTo(x, by + bh + 6); ctx.lineTo(x + 4, by + bh);
   ctx.fillStyle = b.kind === 'speech' ? '#f0ead6' : '#d8e8f8'; ctx.fill();
   ctx.strokeStyle = '#2a2020'; ctx.stroke();
   // Text
   ctx.fillStyle = '#1a1020'; ctx.fillText(b.text, bx + 6, by + 13);
   if (b.kind === 'thought') {
     ctx.fillStyle = '#d8e8f8';
     ctx.beginPath(); ctx.arc(x - 2, by + bh + 10, 2, 0, Math.PI * 2); ctx.fill(); ctx.stroke();
     ctx.beginPath(); ctx.arc(x - 6, by + bh + 14, 1.5, 0, Math.PI * 2); ctx.fill(); ctx.stroke();
   }
   ctx.globalAlpha = 1;
 }

 function roundRect(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, r: number) {
   ctx.beginPath();
   ctx.moveTo(x + r, y); ctx.lineTo(x + w - r, y);
   ctx.quadraticCurveTo(x + w, y, x + w, y + r); ctx.lineTo(x + w, y + h - r);
   ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h); ctx.lineTo(x + r, y + h);
   ctx.quadraticCurveTo(x, y + h, x, y + h - r); ctx.lineTo(x, y + r);
   ctx.quadraticCurveTo(x, y, x + r, y); ctx.closePath();
 }

+// ─── Furniture drawing ─────────────────────────────────────────────
+
+function drawThrone(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Ornate gold throne with red cushion, 28x32 px approx
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Backrest frame (gold)
+  ctx.fillStyle = '#d4af37';
+  ctx.fillRect(4, 0, 20, 28);
+  // Cushion (red)
+  ctx.fillStyle = '#a32a2a';
+  ctx.fillRect(6, 18, 16, 10);
+  // Decorative top arch
+  ctx.beginPath();
+  ctx.moveTo(4, 0);
+  ctx.bezierCurveTo(14, -12, 24, 0, 24, 0);
+  ctx.lineTo(4, 0);
+  ctx.fill();
+  // Legs
+  ctx.fillRect(4, 28, 6, 4);
+  ctx.fillRect(18, 28, 6, 4);
+  ctx.restore();
+}
+
+function drawPlanningTable(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Wood table with map scroll, 30x24 px approx
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Table top (brown wood)
+  ctx.fillStyle = '#6b4c2b';
+  ctx.fillRect(0, 8, 30, 12);
+  // Table legs
+  ctx.fillRect(2, 20, 4, 6);
+  ctx.fillRect(24, 20, 4, 6);
+  // Map scroll (light parchment)
+  ctx.fillStyle = '#d9cba3';
+  ctx.fillRect(6, 10, 18, 8);
+  // Map details (green lines)
+  ctx.strokeStyle = '#3a6b35';
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  ctx.moveTo(8, 12);
+  ctx.lineTo(22, 14);
+  ctx.moveTo(10, 16);
+  ctx.lineTo(20, 18);
+  ctx.stroke();
+  ctx.restore();
+}
+
+function drawWeaponRack(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Weapon rack with sword silhouettes, 28x28 px approx
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Rack frame (dark wood)
+  ctx.fillStyle = '#4a2f1a';
+  ctx.fillRect(2, 4, 24, 20);
+  // Crossbars
+  ctx.fillRect(2, 8, 24, 3);
+  ctx.fillRect(2, 16, 24, 3);
+  // Swords (gray blades)
+  ctx.strokeStyle = '#a0a0a0';
+  ctx.lineWidth = 2;
+  // Sword 1
+  ctx.beginPath();
+  ctx.moveTo(8, 7);
+  ctx.lineTo(8, 21);
+  ctx.moveTo(6, 7);
+  ctx.lineTo(10, 7);
+  // Sword 2
+  ctx.moveTo(16, 7);
+  ctx.lineTo(16, 21);
+  ctx.moveTo(14, 7);
+  ctx.lineTo(18, 7);
+  ctx.stroke();
+  ctx.restore();
+}
+
+function drawWorkbench(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Workbench with tools, 32x24 px approx
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Bench top (medium brown)
+  ctx.fillStyle = '#7a5230';
+  ctx.fillRect(0, 8, 32, 12);
+  // Legs
+  ctx.fillRect(2, 20, 6, 4);
+  ctx.fillRect(24, 20, 6, 4);
+  // Hammer (handle + head)
+  ctx.strokeStyle = '#3a2f2a';
+  ctx.lineWidth = 2;
+  ctx.beginPath();
+  ctx.moveTo(8, 14);
+  ctx.lineTo(8, 18);
+  ctx.moveTo(6, 18);
+  ctx.lineTo(10, 18);
+  ctx.stroke();
+  // Saw blade (gray jagged)
+  ctx.fillStyle = '#a0a0a0';
+  ctx.beginPath();
+  ctx.moveTo(20, 14);
+  for (let i = 0; i < 5; i++) {
+    ctx.lineTo(20 + i * 2, 14 + (i % 2 === 0 ? 4 : 0));
+  }
+  ctx.lineTo(30, 18);
+  ctx.closePath();
+  ctx.fill();
+  ctx.restore();
+}
+
+function drawPotionShelf(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Shelf with colored bottles, 28x28 px approx
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Shelf frame (dark wood)
+  ctx.fillStyle = '#4a2f1a';
+  ctx.fillRect(2, 4, 24, 20);
+  // Shelf boards
+  ctx.fillRect(2, 8, 24, 3);
+  ctx.fillRect(2, 16, 24, 3);
+  // Bottles (red, blue, green)
+  const bottleColors = ['#c33', '#339', '#393'];
+  for (let i = 0; i < 3; i++) {
+    ctx.fillStyle = bottleColors[i];
+    ctx.beginPath();
+    ctx.ellipse(8 + i * 8, 12, 4, 6, 0, 0, Math.PI * 2);
+    ctx.fill();
+    ctx.strokeStyle = '#222';
+    ctx.lineWidth = 1;
+    ctx.stroke();
+  }
+  ctx.restore();
+}
+
+function drawScribeDesk(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Desk with quill and book, 30x24 px approx
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Desk top (light wood)
+  ctx.fillStyle = '#a67c4f';
+  ctx.fillRect(0, 8, 30, 12);
+  // Legs
+  ctx.fillRect(2, 20, 6, 4);
+  ctx.fillRect(22, 20, 6, 4);
+  // Book (dark cover)
+  ctx.fillStyle = '#3a2f2a';
+  ctx.fillRect(6, 12, 10, 6);
+  // Quill (white feather + black tip)
+  ctx.strokeStyle = '#000';
+  ctx.lineWidth = 1.5;
+  ctx.beginPath();
+  ctx.moveTo(20, 12);
+  ctx.lineTo(24, 18);
+  ctx.moveTo(23, 17);
+  ctx.lineTo(25, 15);
+  ctx.stroke();
+  ctx.fillStyle = '#eee';
+  ctx.beginPath();
+  ctx.ellipse(22, 14, 2, 5, Math.PI / 4, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.restore();
+}
+
+function drawHealingBasin(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Basin with glowing water, 28x24 px approx
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Basin base (stone gray)
+  ctx.fillStyle = '#7a7a7a';
+  ctx.beginPath();
+  ctx.ellipse(14, 18, 14, 8, 0, 0, Math.PI * 2);
+  ctx.fill();
+  // Water (blue with glow)
+  const gradient = ctx.createRadialGradient(14, 18, 2, 14, 18, 14);
+  gradient.addColorStop(0, 'rgba(100,180,255,0.8)');
+  gradient.addColorStop(1, 'rgba(0,0,80,0)');
+  ctx.fillStyle = gradient;
+  ctx.beginPath();
+  ctx.ellipse(14, 18, 12, 6, 0, 0, Math.PI * 2);
+  ctx.fill();
+  // Glow particles
+  for (let i = 0; i < 6; i++) {
+    const px = 14 + (Math.random() - 0.5) * 20;
+    const py = 18 + (Math.random() - 0.5) * 12;
+    ctx.fillStyle = 'rgba(100,180,255,0.3)';
+    ctx.beginPath();
+    ctx.arc(px, py, 2, 0, Math.PI * 2);
+    ctx.fill();
+  }
+  ctx.restore();
+}
+
+// Draw furniture pieces by room type
+export function drawFurniture(ctx: CanvasRenderingContext2D, roomType: string, x: number, y: number, scale: number) {
+  switch(roomType) {
+    case 'throneRoom':
+      // Two pieces: Throne and Planning Table
+      drawThrone(ctx, x + 10 * scale, y + 4 * scale, scale);
+      drawPlanningTable(ctx, x + 50 * scale, y + 12 * scale, scale);
+      break;
+    case 'armory':
+      // Weapon Rack and Workbench
+      drawWeaponRack(ctx, x + 8 * scale, y + 8 * scale, scale);
+      drawWorkbench(ctx, x + 48 * scale, y + 12 * scale, scale);
+      break;
+    case 'alchemyLab':
+      // Potion Shelf and Scribe Desk
+      drawPotionShelf(ctx, x + 12 * scale, y + 6 * scale, scale);
+      drawScribeDesk(ctx, x + 52 * scale, y + 14 * scale, scale);
+      break;
+
